INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000001', 'US Survey Foot vs International Foot', 'The US survey foot = 1200/3937 m ≈ 0.30480061 m; the international foot = 0.3048 m exactly. They differ by ~2 ppm, which becomes significant over long distances and in State Plane Coordinates.', 'One is defined exactly as 0.3048 m.', NULL, NULL, 'f5000001-0000-0000-0000-000000000001', ARRAY['units','foot','conversion','state plane']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:m1', 'medium', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000002', 'Gunter''s Chain', 'A traditional survey unit: 1 chain = 66 feet = 100 links. 80 chains = 1 mile; 10 square chains = 1 acre.', '66 feet.', NULL, NULL, 'f5000001-0000-0000-0000-000000000001', ARRAY['chain','links','units']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:m1', 'easy', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000003', 'Acre', 'A unit of area equal to 43,560 square feet, or 10 square chains.', '43,560 ft².', NULL, NULL, 'f5000001-0000-0000-0000-000000000001', ARRAY['acre','area','units']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:m1', 'easy', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000004', 'Accuracy vs Precision', 'Accuracy is how close a measurement is to the true value; precision is how closely repeated measurements agree with one another. A set can be precise but inaccurate.', 'One compares to truth, the other to itself.', NULL, NULL, 'f5000001-0000-0000-0000-000000000001', ARRAY['accuracy','precision','error']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:m1', 'easy', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000005', 'Gross Error (Blunder)', 'A mistake caused by carelessness — misreading, transposing digits, mis-recording. It is not random and must be detected and removed from the data set.', 'A human mistake, not a natural error.', NULL, NULL, 'f5000001-0000-0000-0000-000000000001', ARRAY['blunder','gross error','mistake']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:m1', 'easy', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000006', 'Systematic Error', 'An error that follows a physical law, keeping the same sign and magnitude under the same conditions (e.g., a tape that is too long). It can be modeled and corrected.', 'Same conditions → same error; correctable.', NULL, NULL, 'f5000001-0000-0000-0000-000000000001', ARRAY['systematic','error','correction']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:m1', 'medium', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000007', 'Random Error', 'A small, unavoidable error that follows the normal distribution — equally likely to be positive or negative. It cannot be eliminated but is reduced by repetition and averaging.', 'Follows the bell curve; reduced by averaging.', NULL, NULL, 'f5000001-0000-0000-0000-000000000001', ARRAY['random','error','normal']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:m1', 'medium', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000008', 'Most Probable Value', 'For a set of equally weighted, independent observations, the most probable value is the arithmetic mean: x̄ = Σxᵢ / n.', 'It is just the mean.', NULL, NULL, 'f5000001-0000-0000-0000-000000000001', ARRAY['most probable value','mean','average']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:m1', 'easy', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000009', 'Residual', 'The difference between an individual observation and the most probable value (mean): v = xᵢ − x̄. Residuals are used to compute standard deviation.', 'v = xᵢ − x̄.', NULL, NULL, 'f5000001-0000-0000-0000-000000000001', ARRAY['residual','v','mean']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:m1', 'easy', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000010', 'Sample Standard Deviation', 'A measure of the spread of observations: σ = √( Σv² / (n − 1) ), where v = xᵢ − x̄. The (n − 1) denominator applies to a sample.', 'Divide the sum of squared residuals by (n − 1).', 'Then take the square root.', NULL, 'f5000001-0000-0000-0000-000000000001', ARRAY['standard deviation','sigma','spread']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:m1', 'medium', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000011', 'Standard Error of the Mean', 'The uncertainty of the computed mean: σ_m = σ / √n. Taking more observations shrinks it by the square root of n.', 'Divide σ by √n.', NULL, NULL, 'f5000001-0000-0000-0000-000000000001', ARRAY['standard error','mean','sigma_m']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:m1', 'medium', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000012', 'Error Propagation — Sum', 'When independent random errors add, they combine in quadrature: E_sum = √( E₁² + E₂² + … + Eₙ² ).', 'Root-sum-square of the individual errors.', NULL, NULL, 'f5000001-0000-0000-0000-000000000001', ARRAY['error propagation','sum','quadrature']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:m1', 'medium', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000013', 'Error Propagation — Series', 'For n measurements each carrying the same random error E (e.g., laying a tape n times), the total error is E_series = E·√n.', 'E times the square root of n.', NULL, NULL, 'f5000001-0000-0000-0000-000000000001', ARRAY['error propagation','series','taping']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:m1', 'medium', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000014', 'Relative Precision', 'A ratio expressing precision as 1 : (distance / error) — e.g., an error of 0.1 ft over 500 ft is 1:5000. Larger second number = higher precision.', 'Express as 1 : (distance ÷ error).', NULL, NULL, 'f5000001-0000-0000-0000-000000000001', ARRAY['relative precision','ratio','accuracy ratio']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:m1', 'medium', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000015', '68-95-99.7 Rule', 'For normally distributed data, about 68% of values fall within ±1σ of the mean, ~95% within ±2σ, and ~99.7% within ±3σ.', 'One, two, and three standard deviations.', NULL, NULL, 'f5000001-0000-0000-0000-000000000001', ARRAY['normal distribution','empirical rule','sigma']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:m1', 'easy', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000016', 'Weighted Mean', 'When observations have different reliabilities, the best estimate is x̄_w = Σ(wᵢ·xᵢ) / Σwᵢ, where each weight is inversely proportional to variance: wᵢ ∝ 1/σᵢ².', 'Weight each value, then average.', 'Weight ∝ 1/σ².', NULL, 'f5000001-0000-0000-0000-000000000001', ARRAY['weighted mean','weight','variance']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:m1', 'hard', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000017', 'Weight (in Adjustment)', 'A number expressing the relative reliability of an observation. Weight is inversely proportional to variance: w ∝ 1/σ². More precise observations get more weight.', 'Inversely proportional to variance.', NULL, NULL, 'f5000001-0000-0000-0000-000000000001', ARRAY['weight','variance','adjustment']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:m1', 'medium', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000018', 'Significant Figures', 'The digits in a number that carry real meaning; the last significant figure is the estimated/uncertain one. They govern how results are rounded so precision is not overstated.', 'The last one is the uncertain digit.', NULL, NULL, 'f5000001-0000-0000-0000-000000000001', ARRAY['significant figures','rounding','precision']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:m1', 'easy', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000019', 'Confidence Interval', 'A range that likely contains the true value: x̄ ± Z·σ_m, where Z is the standard-normal multiplier for the confidence level (Z = 1.6449 at 90%, 1.9600 at 95%).', 'Mean ± Z·(standard error).', NULL, NULL, 'f5000001-0000-0000-0000-000000000001', ARRAY['confidence interval','Z','probability']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:m1', 'hard', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb018000-0000-0000-0000-000000000020', '90% and 95% Error (Z-values)', 'Common probable-error multipliers of the standard deviation: the 90% error = 1.6449σ and the 95% error = 1.9600σ.', '≈1.645 and ≈1.96.', NULL, NULL, 'f5000001-0000-0000-0000-000000000001', ARRAY['Z value','90 percent','95 percent','probable error']::text[], ARRAY['fs-flashcards','fs-m1']::text[], 'fs:m1', 'medium', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000001', 'Differential Leveling (HI Method)', 'Determining the elevation of points by reading a rod through a level. The instrument height is found from a known point, then unknown elevations are read from it: HI = Elev + BS, Elev = HI − FS.', 'Backsight up to HI, foresight down to the point.', NULL, NULL, 'f5000002-0000-0000-0000-000000000002', ARRAY['differential leveling','HI','elevation']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:m2', 'easy', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000002', 'Benchmark (BM)', 'A permanent, stable point of known elevation used as a reference/starting point for leveling.', 'Permanent point of known elevation.', NULL, NULL, 'f5000002-0000-0000-0000-000000000002', ARRAY['benchmark','BM','datum']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:m2', 'easy', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000003', 'Turning Point (TP)', 'A temporary point on which a foresight is taken and then the next backsight, allowing the level to be moved forward while carrying elevation along the line.', 'Both an FS and the next BS are taken on it.', NULL, NULL, 'f5000002-0000-0000-0000-000000000002', ARRAY['turning point','TP','leveling']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:m2', 'medium', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000004', 'Backsight (BS)', 'A rod reading taken on a point of known elevation. It is added to that elevation to obtain the Height of Instrument (the "plus sight").', 'Added to elevation → HI.', NULL, NULL, 'f5000002-0000-0000-0000-000000000002', ARRAY['backsight','BS','plus sight']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:m2', 'easy', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000005', 'Foresight (FS)', 'A rod reading on a point of unknown elevation. It is subtracted from the Height of Instrument to get that point’s elevation (the "minus sight").', 'Subtracted from HI → elevation.', NULL, NULL, 'f5000002-0000-0000-0000-000000000002', ARRAY['foresight','FS','minus sight']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:m2', 'easy', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000006', 'Height of Instrument (HI)', 'The elevation of the instrument’s line of sight: HI = Elev_BM + BS. Point elevations are then HI − FS.', 'HI = known elevation + backsight.', NULL, NULL, 'f5000002-0000-0000-0000-000000000002', ARRAY['height of instrument','HI']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:m2', 'easy', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000007', 'Elevation Difference (multi-setup)', 'Over a run with several instrument setups, the net elevation change equals the sum of backsights minus the sum of foresights: ΔElev = ΣBS − ΣFS.', 'Sum of BS minus sum of FS.', NULL, NULL, 'f5000002-0000-0000-0000-000000000002', ARRAY['elevation difference','sum','leveling']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:m2', 'medium', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000008', 'Arithmetic Check', 'A bookkeeping check on a level run: the final minus initial elevation must equal ΣBS − ΣFS. It verifies the math, not the field work.', 'Elev_last − Elev_first = ΣBS − ΣFS.', NULL, NULL, 'f5000002-0000-0000-0000-000000000002', ARRAY['arithmetic check','leveling','bookkeeping']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:m2', 'medium', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000009', 'NAVD88', 'The North American Vertical Datum of 1988 — the standard vertical datum for orthometric heights (elevations) in North America.', 'The standard modern vertical datum.', NULL, NULL, 'f5000002-0000-0000-0000-000000000002', ARRAY['NAVD88','datum','vertical']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:m2', 'easy', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000010', 'Curvature & Refraction Correction', 'Earth curvature makes a distant rod read too high; atmospheric refraction partly offsets it. The combined correction is C_R = 0.0206·F², with F the sight distance in thousands of feet.', '0.0206·F² (F in thousands of ft).', NULL, NULL, 'f5000002-0000-0000-0000-000000000002', ARRAY['curvature','refraction','correction']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:m2', 'hard', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000011', 'Trigonometric Leveling', 'Finding elevation difference from a measured distance and vertical/zenith angle: ΔElev = S·sin(V) = d·tan(V), then add instrument height and subtract rod/target height (+ hi − hr).', 'Slope distance × sin(vertical angle).', NULL, NULL, 'f5000002-0000-0000-0000-000000000002', ARRAY['trigonometric leveling','vertical angle','elevation']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:m2', 'hard', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000012', 'Collimation Error', 'The line of sight is not truly horizontal (not parallel to the leveling axis), so readings are biased with distance. It is detected and quantified by the two-peg test.', 'Line of sight not level; found by the two-peg test.', NULL, NULL, 'f5000002-0000-0000-0000-000000000002', ARRAY['collimation','error','two-peg']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:m2', 'medium', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000013', 'Two-Peg Test', 'A field check for collimation error: compare rod readings taken with the instrument midway between two pegs (errors cancel) to readings taken near one peg (error shows), then solve for the collimation error.', 'Midpoint setup vs end setup.', NULL, NULL, 'f5000002-0000-0000-0000-000000000002', ARRAY['two-peg test','collimation','calibration']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:m2', 'medium', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000014', 'Loop Misclosure', 'The error in a level loop/line: Misclosure = (ΣBS − ΣFS) − (Elev_known_end − Elev_known_start). It is distributed among setups (often by distance) to adjust elevations.', 'Measured Δ minus known Δ.', NULL, NULL, 'f5000002-0000-0000-0000-000000000002', ARRAY['misclosure','loop','adjustment']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:m2', 'medium', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000015', 'Reciprocal Leveling', 'Leveling across a wide obstacle (e.g., a river) by taking readings in both directions so curvature, refraction, and collimation cancel: Δh = ½[(a₁ − b₁) + (a₂ − b₂)].', 'Average the two-direction differences.', NULL, NULL, 'f5000002-0000-0000-0000-000000000002', ARRAY['reciprocal leveling','river','obstacle']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:m2', 'hard', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000016', 'Three-Wire Leveling', 'Reading the upper, middle, and lower stadia wires; the mean = (U + M + L)/3 gives a checked rod reading, and the wire interval gives the sight distance for balancing.', 'Average of three stadia-wire readings.', NULL, NULL, 'f5000002-0000-0000-0000-000000000002', ARRAY['three-wire','stadia','leveling']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:m2', 'medium', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000017', 'Balancing BS/FS Distances', 'Keeping backsight and foresight distances equal at each setup cancels collimation error, earth curvature, and refraction — a core good-practice of precise leveling.', 'Equal sight lengths cancel systematic errors.', NULL, NULL, 'f5000002-0000-0000-0000-000000000002', ARRAY['balancing','backsight','foresight']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:m2', 'medium', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000018', 'Profile Leveling', 'Taking a series of elevations at intervals along a line (e.g., a route centerline) to plot a vertical profile of the ground.', 'Elevations along a line → a profile.', NULL, NULL, 'f5000002-0000-0000-0000-000000000002', ARRAY['profile leveling','centerline','profile']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:m2', 'easy', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000019', 'Curvature-Only Correction', 'The elevation error from earth curvature alone (no refraction) on a rod reading: C = 0.0240·F², with F in thousands of feet.', '0.0240·F² (F in thousands of ft).', NULL, NULL, 'f5000002-0000-0000-0000-000000000002', ARRAY['curvature','correction']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:m2', 'hard', true, 'approved');
INSERT INTO flashcards (id, term, definition, hint_1, hint_2, hint_3, module_id, keywords, tags, category, difficulty_level, is_published, review_status) VALUES ('fb028000-0000-0000-0000-000000000020', 'Datum (Vertical)', 'The reference surface from which elevations are measured (e.g., NAVD88, or mean sea level for older NGVD29). All benchmark elevations tie to a datum.', 'The zero surface for elevations.', NULL, NULL, 'f5000002-0000-0000-0000-000000000002', ARRAY['datum','vertical','elevation']::text[], ARRAY['fs-flashcards','fs-m2']::text[], 'fs:m2', 'easy', true, 'approved');
