-- 402_fs_prep_flashcards.sql (GENERATED) — built-in FS study flashcards
-- Source: fs/m<n>.json flashcards[]. Namespaced by tag 'fs-flashcards'/'fs-m<n>',
-- category 'fs:m<n>', deterministic UUIDs — idempotent, DELETE-then-INSERT per module.
-- Depends on: 401 (flashcards table DDL).
BEGIN;

-- ===== FS Module 1 flashcards (20) =====
DELETE FROM flashcards WHERE module_id='f5000001-0000-0000-0000-000000000001' AND 'fs-flashcards' = ANY(tags);

-- ===== FS Module 2 flashcards (20) =====
DELETE FROM flashcards WHERE module_id='f5000002-0000-0000-0000-000000000002' AND 'fs-flashcards' = ANY(tags);

SELECT 'FS flashcards: ' || (SELECT count(*) FROM flashcards WHERE 'fs-flashcards'=ANY(tags)) || ' built-in cards.' AS status;
COMMIT;
